spec.expr:
sum by (instance, gpu_id) (
  amd_gpu_gfx_activity{
    job="amd_metrics_exporter",
    instance=~"$host",
    gpu_id=~"$gpu_id"
  }
)

sum by (instance, gpu_id) (
  amd_gpu_umc_activity{
    job="amd_metrics_exporter",
    instance=~"$host",
    gpu_id=~"$gpu_id"
  }
)

sum by (instance) (
  amd_gpu_used_vram{
    job="amd_metrics_exporter",
    instance=~"$host",
    gpu_id=~"$gpu_id"
  }
)
